  KEY `Loan_id` (`Loan_id`),
  CONSTRAINT `reservation_ibfk_1` FOREIGN KEY (`Book_id`) REFERENCES `book` (`Book_id`),
  CONSTRAINT `reservation_ibfk_2` FOREIGN KEY (`Member_id`) REFERENCES `members` (`Member_id`),
  CONSTRAINT `reservation_ibfk_3` FOREIGN KEY (`Loan_id`) REFERENCES `loan` (`Loan_id`)
